def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        for step in range(5):
            if residual <= 0:
                score += 10 + step
            else:
                score += (1 / (residual + step + 1)) * (step + 1)
            residual *= 0.6 if step % 2 == 0 else 0.4
        if capacity > 3 * item:
            for multiplier in [0.95, 0.85, 0.75]:
                score *= multiplier
                if score < 5:
                    break
        else:
            penalty_factor = 1.1
            for _ in range(3):
                if capacity < item * 1.2:
                    penalty_factor += 0.05
                else:
                    penalty_factor -= 0.03
            score *= penalty_factor
        if score > 100:
            priorities[i] = 100
        elif score < 0:
            priorities[i] = 0
        else:
            priorities[i] = score
    return priorities
